args.query:
SELECT COUNT(*) AS c
FROM "Case"
WHERE createddate::date >= DATE '2020-06-10' AND createddate::date < DATE '2021-04-10'
  AND regexp_replace(orderitemid__c, '^#', '') IN (
    SELECT regexp_replace(id, '^#', '') FROM orderitem__c WHERE 1=0
  );

